// Platform-owned tables (gateway_* prefix is historical)

export {
  type GatewayBackfillRun,
  gatewayBackfillRuns,
  type InsertGatewayBackfillRun,
} from "./gateway-backfill-runs";
export {
  type GatewayInstallation,
  gatewayInstallations,
  type InsertGatewayInstallation,
} from "./gateway-installations";
export {
  type GatewayLifecycleLog,
  gatewayLifecycleLogs,
  type InsertGatewayLifecycleLog,
} from "./gateway-lifecycle-log";
export {
  type GatewayToken,
  gatewayTokens,
  type InsertGatewayToken,
} from "./gateway-tokens";
export {
  type GatewayWebhookDelivery,
  gatewayWebhookDeliveries,
  type InsertGatewayWebhookDelivery,
} from "./gateway-webhook-deliveries";
// Organization API Keys (org-scoped authentication)
export {
  type InsertOrgApiKey,
  type OrgApiKey,
  orgApiKeys,
} from "./org-api-keys";
// Org entities
export {
  type InsertOrgEntity,
  type OrgEntity,
  orgEntities,
} from "./org-entities";
// Entity↔entity edges
export {
  type InsertOrgEntityEdge,
  type OrgEntityEdge,
  orgEntityEdges,
} from "./org-entity-edges";
// Entity-event junction
export {
  type InsertOrgEventEntity,
  type OrgEventEntity,
  orgEventEntities,
} from "./org-event-entities";
// Org events (neural observations)
export {
  type InsertOrgEvent,
  type OrgEvent,
  orgEvents,
} from "./org-events";
// Org ingest log (raw webhook ingress log)
export {
  type InsertOrgIngestLog,
  type OrgIngestLog,
  orgIngestLogs,
} from "./org-ingest-logs";
export {
  type InsertOrgIntegration,
  type OrgIntegration,
  orgIntegrations,
} from "./org-integrations";
// Org repo indexes (.lightfast repo indexing)
export {
  type InsertOrgRepoIndex,
  type OrgRepoIndex,
  orgRepoIndexes,
} from "./org-repo-indexes";
export {
  type InsertOrgUserActivity,
  type OrgUserActivity,
  orgUserActivities,
} from "./org-user-activities";
export type { WorkflowInput, WorkflowOutput } from "./org-workflow-runs";
export {
  type InsertOrgWorkflowRun,
  type OrgWorkflowRun,
  orgWorkflowRuns,
} from "./org-workflow-runs";
// Pending installations (pre-org GitHub App installs)
export {
  type InsertPendingInstallation,
  type PendingInstallation,
  pendingInstallations,
} from "./pending-installations";

import type { ProviderAccountInfo, SourceType } from "@repo/app-providers";
import type { GwInstallationBackfillConfig } from "@repo/app-providers/contracts";
import type { ClerkUserId } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  index,
  integer,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const gatewayInstallations = pgTable(
  "lightfast_gateway_installations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),
    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),
    orgId: varchar("org_id", { length: 191 }).notNull(),

    providerOrgId: varchar("provider_org_id", { length: 191 }),
    providerOrgLogin: varchar("provider_org_login", { length: 191 }),

    status: varchar("status", { length: 50 }).notNull(), // active|pending|error|revoked

    /**
     * Provider-specific installation metadata (JSONB) — discriminated union by sourceType.
     *
     * Schema: providerAccountInfoSchema from @repo/app-providers
     *
     * DESIGN INVARIANT:
     * - `raw` = non-secret fields from the token exchange / OAuth response only
     * - NEVER store display names (account login, org name, avatar, slug) here
     * - Display data is resolved live via provider APIs in connections.*.list/get
     * - This column stores identity + operational data, not presentation data
     *
     * NEVER add resource-specific data (repos[], projects[], teams[]) — those
     * belong in providerConfig on gateway_installations, one row per resource.
     */
    providerAccountInfo: jsonb(
      "provider_account_info"
    ).$type<ProviderAccountInfo>(),

    /** Optional backfill configuration for this installation. */
    backfillConfig:
      jsonb("backfill_config").$type<GwInstallationBackfillConfig>(),

    // Health monitoring columns
    healthStatus: varchar("health_status", { length: 50 })
      .notNull()
      .default("unknown"),
    lastHealthCheckAt: timestamp("last_health_check_at", {
      mode: "string",
      withTimezone: true,
    }),
    healthCheckFailures: integer("health_check_failures").notNull().default(0),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
    updatedAt: timestamp("updated_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow()
      .$onUpdateFn(() => sql`CURRENT_TIMESTAMP`),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("gateway_inst_provider_external_idx").on(
      table.provider,
      table.externalId
    ),
    orgIdIdx: index("gateway_inst_org_id_idx").on(table.orgId),
    orgProviderIdx: index("gateway_inst_org_provider_idx").on(
      table.orgId,
      table.provider
    ),
    connectedByIdx: index("gateway_inst_connected_by_idx").on(
      table.connectedBy
    ),
    providerOrgIdx: uniqueIndex("gateway_inst_provider_org_idx").on(
      table.provider,
      table.providerOrgId
    ),
  })
);

export type GatewayInstallation = typeof gatewayInstallations.$inferSelect;
export type InsertGatewayInstallation =
  typeof gatewayInstallations.$inferInsert;

import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { gatewayInstallations } from "./gateway-installations";

export const gatewayTokens = pgTable(
  "lightfast_gateway_tokens",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    installationId: varchar("installation_id", { length: 191 })
      .notNull()
      .references(() => gatewayInstallations.id, { onDelete: "cascade" }),

    accessToken: text("access_token").notNull(), // AES-256-GCM encrypted
    refreshToken: text("refresh_token"),
    expiresAt: timestamp("expires_at", { mode: "string", withTimezone: true }),
    tokenType: varchar("token_type", { length: 50 }),
    scope: text("scope"),

    updatedAt: timestamp("updated_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow()
      .$onUpdateFn(() => sql`CURRENT_TIMESTAMP`),
  },
  (table) => ({
    installationIdIdx: uniqueIndex("gateway_tok_installation_id_idx").on(
      table.installationId
    ),
  })
);

export type GatewayToken = typeof gatewayTokens.$inferSelect;
export type InsertGatewayToken = typeof gatewayTokens.$inferInsert;

import type { EntityCategory } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  integer,
  jsonb,
  pgTable,
  real,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

/**
 * Org entities extracted from events
 *
 * Stores structured entities discovered in event content.
 * Entities are deduplicated by (clerkOrgId, category, key) and
 * occurrence counts track how many times each entity is seen.
 */
export const orgEntities = pgTable(
  "lightfast_org_entities",
  {
    /**
     * Internal BIGINT primary key - maximum join/query performance
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * External identifier for API responses
     */
    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // ========== ENTITY IDENTITY ==========

    /**
     * Entity category (engineer, project, endpoint, etc.)
     */
    category: varchar("category", { length: 50 })
      .notNull()
      .$type<EntityCategory>(),

    /**
     * Canonical entity key (e.g., "@sarah", "POST /api/users", "#123")
     */
    key: varchar("key", { length: 500 }).notNull(),

    /**
     * Human-readable value/description
     */
    value: text("value"),

    /**
     * Alternative names for this entity (e.g., ["sarah@acme.com", "Sarah J"])
     */
    aliases: jsonb("aliases").$type<string[]>(),

    // ========== PROVENANCE ==========

    /**
     * Text snippet providing evidence for extraction
     */
    evidenceSnippet: text("evidence_snippet"),

    /**
     * Extraction confidence score (0.0 - 1.0)
     */
    confidence: real("confidence").default(0.8),

    /**
     * Entity lifecycle state (e.g., "open", "merged", "resolved", "closed")
     */
    state: varchar("state", { length: 100 }),

    /**
     * Canonical source URL for this entity
     */
    url: varchar("url", { length: 2048 }),

    // ========== METRICS ==========

    /**
     * When this entity was first extracted
     */
    extractedAt: timestamp("extracted_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    /**
     * When this entity was last seen in an event
     */
    lastSeenAt: timestamp("last_seen_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    /**
     * Number of times this entity has been extracted
     */
    occurrenceCount: integer("occurrence_count").default(1).notNull(),

    // ========== TIMESTAMPS ==========

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    updatedAt: timestamp("updated_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // External ID lookup (API requests)
    externalIdIdx: uniqueIndex("org_entity_external_id_idx").on(
      table.externalId
    ),

    // Unique constraint for deduplication — (clerkOrgId, category, key)
    uniqueEntityKey: uniqueIndex("org_entity_clerk_org_category_key_idx").on(
      table.clerkOrgId,
      table.category,
      table.key
    ),

    // Lookup by org and category
    orgCategoryIdx: index("org_entity_org_category_idx").on(
      table.clerkOrgId,
      table.category
    ),

    // Key search
    orgKeyIdx: index("org_entity_org_key_idx").on(table.clerkOrgId, table.key),

    // Last seen for cleanup/ranking
    orgLastSeenIdx: index("org_entity_org_last_seen_idx").on(
      table.clerkOrgId,
      table.lastSeenAt
    ),
  })
);

// Type exports
export type OrgEntity = typeof orgEntities.$inferSelect;
export type InsertOrgEntity = typeof orgEntities.$inferInsert;

import type { EntityRelation } from "@repo/app-providers/contracts";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgIngestLogs } from "./org-ingest-logs";

/**
 * Org events - atomic engineering events from GitHub, Vercel, etc.
 */
export const orgEvents = pgTable(
  "lightfast_org_events",
  {
    /**
     * Internal BIGINT primary key - maximum join/query performance
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * External identifier for API responses and Pinecone metadata
     */
    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // ========== TEMPORAL ==========

    /**
     * When the event occurred in the source system
     */
    occurredAt: timestamp("occurred_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),

    /**
     * When the event was captured
     */
    capturedAt: timestamp("captured_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    // ========== CONTENT ==========

    /**
     * Observation type (e.g., "pr_merged", "deployment_succeeded")
     */
    observationType: varchar("observation_type", { length: 100 }).notNull(),

    /**
     * Short title (<=120 chars, embeddable headline)
     */
    title: text("title").notNull(),

    /**
     * Full content for detailed embedding
     */
    content: text("content").notNull(),

    // ========== SOURCE ==========

    /**
     * Source system (github, vercel, linear, sentry)
     */
    source: varchar("source", { length: 50 }).notNull(),

    /**
     * Source-specific event type (e.g., "pull_request_merged")
     */
    sourceType: varchar("source_type", { length: 100 }).notNull(),

    /**
     * Unique source identifier (e.g., "pr:lightfastai/lightfast#123")
     */
    sourceId: varchar("source_id", { length: 255 }).notNull(),

    /**
     * References to related entities
     */
    sourceReferences: jsonb("source_references").$type<EntityRelation[]>(),

    /**
     * Source-specific attributes
     */
    metadata:
      jsonb("metadata").$type<
        Record<string, string | number | boolean | null>
      >(),

    // ========== INGESTION ==========

    /**
     * How this event was ingested: webhook, backfill, manual, or api
     */
    ingestionSource: varchar("ingestion_source", { length: 20 })
      .default("webhook")
      .notNull(),

    /**
     * FK back to the ingest log that produced this event.
     * Null for backfill-ingested events and test-data paths.
     */
    ingestLogId: bigint("ingest_log_id", { mode: "number" }).references(
      () => orgIngestLogs.id,
      { onDelete: "set null" }
    ),

    /**
     * Significance score (0-100) computed at ingestion time.
     * Used for search ranking and notification thresholds.
     * Null for events ingested before this column was added.
     */
    significanceScore: integer("significance_score"),

    // ========== TIMESTAMPS ==========

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // External ID lookup (API requests)
    externalIdIdx: uniqueIndex("org_event_external_id_idx").on(
      table.externalId
    ),

    // Org + time range queries
    orgOccurredIdx: index("org_event_org_occurred_idx").on(
      table.clerkOrgId,
      table.occurredAt
    ),

    // Source filtering
    sourceIdx: index("org_event_source_idx").on(
      table.clerkOrgId,
      table.source,
      table.sourceType
    ),

    // Deduplication by source ID
    sourceIdIdx: index("org_event_source_id_idx").on(
      table.clerkOrgId,
      table.sourceId
    ),

    // Type filtering
    typeIdx: index("org_event_type_idx").on(
      table.clerkOrgId,
      table.observationType
    ),
  })
);

// Type exports
export type OrgEvent = typeof orgEvents.$inferSelect;
export type InsertOrgEvent = typeof orgEvents.$inferInsert;

import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  boolean,
  index,
  pgTable,
  text,
  timestamp,
  varchar,
} from "drizzle-orm/pg-core";

/**
 * Organization API Keys table for org-scoped API authentication
 *
 * Org-scoped: Each key authenticates the org and can access all resources
 * within that org.
 *
 * Design:
 * - Each org can have multiple API keys
 * - Keys are stored as hashed values (NEVER store plaintext)
 * - Display only last 4 characters of key to user
 * - Support key expiration and revocation
 * - Track last used timestamp for security auditing
 * - Track created by user for audit trail
 */
export const orgApiKeys = pgTable(
  "lightfast_workspace_api_keys", // Keep original table name to avoid rename migration
  {
    /**
     * Unique API key identifier
     * Using BIGINT for high-volume table (consistent with Phase 5 migration)
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * Public key ID for external reference (nanoid)
     * Used in API responses and URLs instead of exposing BIGINT
     */
    publicId: varchar("public_id", { length: 191 })
      .notNull()
      .unique()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk Org ID — sole scoping mechanism for the key
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    /**
     * User who created this key (audit trail)
     */
    createdByUserId: varchar("created_by_user_id", { length: 191 }).notNull(),

    /**
     * User-provided name/description for the key
     * e.g., "Production API", "CI/CD Pipeline", "Development"
     */
    name: varchar("name", { length: 100 }).notNull(),

    /**
     * Hashed API key value (NEVER store plaintext)
     * Uses SHA-256 hashing
     */
    keyHash: text("key_hash").notNull(),

    /**
     * Key prefix for identification (e.g., "sk-lf-")
     * Helps users identify key type without exposing full key
     */
    keyPrefix: varchar("key_prefix", { length: 20 }).notNull(),

    /**
     * Last 4 characters of the original key (for display purposes)
     */
    keySuffix: varchar("key_suffix", { length: 4 }).notNull(),

    /**
     * Whether this key is currently active
     * Allows soft deletion/revocation
     */
    isActive: boolean("is_active").notNull().default(true),

    /**
     * Optional expiration timestamp
     * If set, key becomes invalid after this time
     */
    expiresAt: timestamp("expires_at", {
      mode: "string",
      withTimezone: true,
    }),

    /**
     * Last time this key was used
     * Updated on each authenticated request
     */
    lastUsedAt: timestamp("last_used_at", {
      mode: "string",
      withTimezone: true,
    }),

    /**
     * IP address of last usage (for security auditing)
     */
    lastUsedFromIp: varchar("last_used_from_ip", { length: 45 }),

    /**
     * Timestamp when key was created
     */
    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    /**
     * Timestamp when key was last updated
     */
    updatedAt: timestamp("updated_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // Index for org-level queries
    clerkOrgIdIdx: index("ws_api_key_clerk_org_id_idx").on(table.clerkOrgId),

    // Index for efficient key validation (hash lookup)
    keyHashIdx: index("ws_api_key_hash_idx").on(table.keyHash),

    // Index for active keys lookup
    isActiveIdx: index("ws_api_key_is_active_idx").on(table.isActive),

    // Composite for org + active keys
    clerkOrgActiveIdx: index("org_api_key_clerk_org_active_idx").on(
      table.clerkOrgId,
      table.isActive
    ),
  })
);

// Type exports
export type OrgApiKey = typeof orgApiKeys.$inferSelect;
export type InsertOrgApiKey = typeof orgApiKeys.$inferInsert;

import type { ProviderConfig, SourceType } from "@repo/app-providers";
import type { SourceIdentifier } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  index,
  integer,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { gatewayInstallations } from "./gateway-installations";

/**
 * Org Sources
 *
 * Specific resources actively syncing to an org.
 * This is what shows up on the "Sources" page in the UI.
 *
 * Flow:
 * 1. User picks a repo/team/project to connect
 * 2. We create an orgIntegration linking the installation to the org
 * 3. Background jobs sync data from this source
 *
 * Example: "acme/frontend repo syncing to acme org"
 */
export const orgIntegrations = pgTable(
  "lightfast_org_integrations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    // Clerk org ID (no FK — Clerk is source of truth)
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // Gateway installation FK (org-scoped)
    installationId: varchar("installation_id", { length: 191 })
      .notNull()
      .references(() => gatewayInstallations.id, { onDelete: "cascade" }),

    // Denormalized provider for fast filtering (replaces providerConfig.sourceType join)
    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),

    /**
     * Provider-specific type and sync settings (JSONB).
     *
     * Schema: providerConfigSchema from @repo/app-providers
     * Fields: provider, type, sync (events + autoSync), status (GitHub only)
     *
     * Resource IDs live in providerResourceId (indexed column), not here.
     */
    providerConfig: jsonb("provider_config").$type<ProviderConfig>().notNull(),

    /**
     * Fast lookup field for provider-specific resource IDs.
     * This is indexed for performance on queries like "find all sources for repoId X".
     *
     * Examples:
     * - GitHub: repoId (e.g., "567890123")
     * - Vercel: projectId (e.g., "prj_123456")
     */
    providerResourceId: varchar("provider_resource_id", { length: 191 })
      .notNull()
      .$type<SourceIdentifier>(),

    // Status
    status: varchar("status", { length: 50 }).notNull().default("active"),
    statusReason: varchar("status_reason", { length: 100 }),

    // Document count (denormalized for performance)
    documentCount: integer("document_count").notNull().default(0),

    // Timestamps
    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
    updatedAt: timestamp("updated_at", { mode: "string", withTimezone: true })
      .notNull()
      .default(sql`CURRENT_TIMESTAMP`),
  },
  (table) => ({
    clerkOrgIdIdx: index("org_integration_clerk_org_id_idx").on(
      table.clerkOrgId
    ),
    installationIdIdx: index("org_integration_installation_id_idx").on(
      table.installationId
    ),
    statusIdx: index("org_integration_status_idx").on(table.status),
    providerResourceIdIdx: index("org_integration_provider_resource_id_idx").on(
      table.providerResourceId
    ),
    providerResourceStatusIdx: index(
      "org_integration_provider_resource_status_idx"
    ).on(table.providerResourceId, table.status),
    installationResourceIdx: uniqueIndex(
      "org_integration_installation_resource_idx"
    ).on(table.installationId, table.providerResourceId),
  })
);

// Type exports
export type OrgIntegration = typeof orgIntegrations.$inferSelect;
export type InsertOrgIntegration = typeof orgIntegrations.$inferInsert;

import type { PostTransformEvent } from "@repo/app-providers/contracts";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  jsonb,
  pgTable,
  timestamp,
  varchar,
} from "drizzle-orm/pg-core";

/**
 * Org Ingest Log stores transformed PostTransformEvent objects
 * produced by the ingress pipeline's per-provider transformers.
 *
 * Only successfully transformed events are stored (unsupported event types
 * are skipped). Raw payloads exist upstream in QStash and gatewayWebhookDeliveries.
 *
 * Primary consumers:
 * - SSE endpoint (/api/gateway/stream) — catch-up on reconnect via Last-Event-ID
 * - Future: dashboard real-time feed, agent VM notifications
 *
 * The BIGINT identity PK serves as a monotonic cursor for SSE Last-Event-ID.
 */
export const orgIngestLogs = pgTable(
  "lightfast_org_ingest_logs",
  {
    /**
     * Monotonic cursor — used as SSE Last-Event-ID for catch-up on reconnect.
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    /**
     * Delivery ID from the platform ingest pipeline — traces back to gatewayWebhookDeliveries for debugging.
     */
    deliveryId: varchar("delivery_id", { length: 191 }).notNull(),

    /**
     * Full transformed event — the canonical event representation.
     * Contains: deliveryId, sourceId, provider, eventType, occurredAt,
     * entity, relations, title, body, attributes.
     */
    sourceEvent: jsonb("source_event").$type<PostTransformEvent>().notNull(),

    /**
     * How this event was ingested: webhook, backfill, manual, or api.
     */
    ingestionSource: varchar("ingestion_source", { length: 20 })
      .default("webhook")
      .notNull(),

    /**
     * When the original webhook was received by the platform ingest service.
     */
    receivedAt: timestamp("received_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),

    /**
     * When this record was created.
     */
    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    /**
     * SSE catch-up: WHERE clerk_org_id = ? AND id > ? ORDER BY id LIMIT 1000
     * Composite index enables efficient B-tree range scan.
     */
    orgEventCursorIdx: index("org_event_cursor_idx").on(
      table.clerkOrgId,
      table.id
    ),

    /**
     * Trace back to the platform ingest delivery record for debugging.
     */
    eventDeliveryIdx: index("org_event_delivery_idx").on(table.deliveryId),

    /**
     * Filter events by provider (replaces dropped source/sourceType columns).
     * Expression index on JSONB provider field.
     */
    eventProviderIdx: index("org_ingest_log_provider_idx").on(
      sql`(${table.sourceEvent}->>'provider')`
    ),

    /**
     * Date-range filtering: WHERE clerk_org_id = ? AND received_at >= ?
     */
    orgEventDateIdx: index("org_event_date_idx").on(
      table.clerkOrgId,
      table.receivedAt
    ),
  })
);

// Type exports
export type OrgIngestLog = typeof orgIngestLogs.$inferSelect;
export type InsertOrgIngestLog = typeof orgIngestLogs.$inferInsert;

import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  boolean,
  index,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgIntegrations } from "./org-integrations";

/**
 * Org Repo Indexes — indexed repositories for AI context injection
 *
 * Day 1: caches README.md from the org's .lightfast GitHub repo and
 * injects it into the Answer agent's system prompt.
 *
 * Future: tracks sync state for full repo vector indexing via Pinecone
 * (layer: "repo-index"). The `cachedContent` column becomes deprecated
 * when retrieval moves to semantic search over Pinecone vectors.
 */
export const orgRepoIndexes = pgTable(
  "lightfast_org_repo_indexes",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    /** Clerk Org ID — one indexed repo per org (day 1) */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    /** FK to orgIntegrations — the connected .lightfast repo source */
    integrationId: varchar("integration_id", { length: 191 })
      .notNull()
      .references(() => orgIntegrations.id, { onDelete: "cascade" }),

    /** GitHub repo full name for display (e.g., "acme/.lightfast") */
    repoFullName: varchar("repo_full_name", { length: 255 }).notNull(),

    /** Denormalized numeric repo ID for webhook lookup */
    providerResourceId: varchar("provider_resource_id", {
      length: 191,
    }).notNull(),

    /**
     * Cached content for direct prompt injection (day 1: README.md).
     * Will be deprecated when retrieval moves to Pinecone vectors.
     */
    cachedContent: text("cached_content"),

    /** GitHub file SHA — for conditional fetching */
    contentSha: varchar("content_sha", { length: 64 }),

    /** Last synced git commit SHA — for incremental sync in Pinecone era */
    lastSyncCommitSha: varchar("last_sync_commit_sha", { length: 64 }),

    /** Whether continuous sync is active */
    isActive: boolean("is_active").notNull().default(true),

    /** Indexing status — tracks sync lifecycle */
    indexingStatus: varchar("indexing_status", { length: 50 })
      .notNull()
      .default("idle"),

    /** Last successful sync timestamp */
    lastSyncedAt: timestamp("last_synced_at", {
      mode: "string",
      withTimezone: true,
    }),

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    updatedAt: timestamp("updated_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    clerkOrgIdIdx: uniqueIndex("org_repo_index_clerk_org_id_idx").on(
      table.clerkOrgId
    ),
    integrationIdIdx: index("org_repo_index_integration_id_idx").on(
      table.integrationId
    ),
    providerResourceIdIdx: index("org_repo_index_provider_resource_id_idx").on(
      table.providerResourceId
    ),
  })
);

export type OrgRepoIndex = typeof orgRepoIndexes.$inferSelect;
export type InsertOrgRepoIndex = typeof orgRepoIndexes.$inferInsert;

