      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),

    providerOrgId: varchar("provider_org_id", { length: 191 }).notNull(),
    providerOrgLogin: varchar("provider_org_login", { length: 191 }).notNull(),
    providerOrgAvatarUrl: varchar("provider_org_avatar_url", { length: 500 }),

    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),

    providerAccountInfo: jsonb(
      "provider_account_info"
    ).$type<ProviderAccountInfo>(),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("pending_inst_provider_external_idx").on(
